import{_ as r,o as e,c as a,j as t,a as o,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"1.6.造物规则","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/1.核心规则/1.6.造物规则.md","filePath":"1.基础规则/1.核心规则/1.6.造物规则.md"}'),l={name:"1.基础规则/1.核心规则/1.6.造物规则.md"};function n(_,d,p,c,i,h){return e(),a("div",null,[...d[0]||(d[0]=[t("h1",{id:"_1-6-造物规则",tabindex:"-1"},[o("1.6.造物规则 "),t("a",{class:"header-anchor",href:"#_1-6-造物规则","aria-label":'Permalink to "1.6.造物规则"'},"​")],-1),t("table",{class:"bannerparthead"},[t("tbody",null,[t("tr",{id:"hdr"},[t("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),s('<h1 id="造物规则" tabindex="-1">造物规则 <a class="header-anchor" href="#造物规则" aria-label="Permalink to &quot;造物规则&quot;">​</a></h1><p>造物规则</p><p>造物规则广泛的指所有资源提供的对某些特定物品的制造能力的拓展会规范应用。当然，制造一种物品虽为基础规则，但主持人仍有权禁止一种物品的制造从而限制其只能以直接购买的形式获取。<br> 造物规则包括但不限于对于一本典籍的编撰、制造一件可以制造的物品等<br> 制造物品需要拥有规定的造物技能与专业，一般情况下为学识-专业：编撰典籍或手艺-制造物品或器用-制造物品，具体情况具体规定。制造物品首先需要获得其原材料，并对其进行加工制造，因此，一名轮回者几乎无法在主神空间以外的地方徒手或仅有简陋工具的情况下制造一件精密的物品。具体是否可以制造，则由主持人进行评判<br> 材料的价格为物品标价的七折，而制造那件物品需进行对应的属性-技能-制造类专业进行检定，进行制造检定是一个根据物品支线等级增加时长的延长检定，当延长检定数累计通过对应制作难度时，视为成功制造；当四次延长检定的成功数未通过时，则视为制造失败，返还购买材料价格的七成。</p><table border="1" style="font-size:13px;"><tbody><tr><td>物品等级</td><td>延长检定所需时间</td><td>制作难度（DC）</td><td>上限时间</td></tr><tr><td>无支线</td><td>15分钟</td><td>12</td><td>1小时</td></tr><tr><td>D级</td><td>30分钟</td><td>20</td><td>2小时</td></tr><tr><td>C级</td><td>1小时</td><td>52</td><td>4小时</td></tr><tr><td>B级</td><td>2小时</td><td>84</td><td>8小时</td></tr><tr><td>A级</td><td>4小时</td><td>120</td><td>16小时</td></tr><tr><td>S级</td><td>6小时</td><td>169</td><td>24小时</td></tr></tbody><colgroup><col> <col> <col> <col></colgroup></table><p>当造物规则的造物被以其他非评级形式折算价值时，视为只有一半价值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(l,[["render",n]]);export{f as __pageData,m as default};
